function measureRouteDistance(start: [number, number, number], pathPoints: [number, number, number][]): number {
    let total = 0;
    let previous = start;

    pathPoints.forEach((point) => {
        total += Math.hypot(point[0] - previous[0], point[2] - previous[2]);
        previous = point;
    });

    return total;
}

