function measureSurfacePathDistance(
    startPoint: { x: number; y: number },
    pathPoints: Array<{ x: number; y: number }>,
): number {
    let total = 0;
    let previous = startPoint;

    pathPoints.forEach((point) => {
        total += Math.hypot(point.x - previous.x, point.y - previous.y);
        previous = point;
    });

    return total;
}

