function measureTransitPathDistance(startPoint: TransitPoint, pathPoints: TransitPoint[]): number {
    let total = 0;
    let previous = startPoint;

    pathPoints.forEach((point) => {
        total += measureTransitDistance(previous, point);
        previous = point;
    });

    return total;
}

